import json
import boto3
import logging
import os

logger = logging.getLogger()
logger.setLevel(logging.INFO)

s3 = boto3.client('s3')
sns = boto3.client('sns')

def lambda_handler(event, context):
    try:
        # Extract bucket name and object key from the event
        bucket_name = event['Records'][0]['s3']['bucket']['name']
        object_key = event['Records'][0]['s3']['object']['key']
        
        # Log the event
        logger.info(f"Processing file {object_key} from bucket {bucket_name}")
        
        # Read the image from S3
        response = s3.get_object(Bucket=bucket_name, Key=object_key)
        image_data = response['Body'].read()
        
        # Process the image (dummy processing for example)
        processed_data = image_data  # Replace with actual processing logic
        
        # Write the processed image back to S3
        processed_key = f"processed/{object_key}"
        s3.put_object(Bucket=bucket_name, Key=processed_key, Body=processed_data)
        
        # Send a notification via SNS
        sns_topic_arn = os.environ['SNS_TOPIC_ARN']
        sns.publish(
            TopicArn=sns_topic_arn,
            Message=f"Image {object_key} processed and saved as {processed_key}",
            Subject="Image Processing Complete"
        )
        
        # Log completion
        logger.info(f"Image {object_key} processed successfully")
        
    except Exception as e:
        logger.error(f"Error processing image: {str(e)}")
        raise

